/**
 * Starburst path: sharp spike tips, smooth concave arc valleys (no inner points).
 * Uses a cubic bezier (C) from each spike tip to the next, with both control
 * points pulled inward to create the concave scoop.
 */
function starburstPath(
  cx: number,
  cy: number,
  outerR: number,
  innerR: number,
  numPoints: number
) {
  const step = (2 * Math.PI) / numPoints;
  let d = "";

  for (let i = 0; i < numPoints; i++) {
    const tipAngle = step * i - Math.PI / 2;
    const tx = cx + outerR * Math.cos(tipAngle);
    const ty = cy + outerR * Math.sin(tipAngle);

    const nextTipAngle = step * (i + 1) - Math.PI / 2;
    const ntx = cx + outerR * Math.cos(nextTipAngle);
    const nty = cy + outerR * Math.sin(nextTipAngle);

    // Two control points at innerR, spread between the two spike tips
    const cp1Angle = tipAngle + step * 0.3;
    const cp2Angle = tipAngle + step * 0.7;
    const c1x = cx + innerR * Math.cos(cp1Angle);
    const c1y = cy + innerR * Math.sin(cp1Angle);
    const c2x = cx + innerR * Math.cos(cp2Angle);
    const c2y = cy + innerR * Math.sin(cp2Angle);

    if (i === 0) d += `M ${tx} ${ty} `;
    d += `C ${c1x} ${c1y} ${c2x} ${c2y} ${ntx} ${nty} `;
  }
  d += "Z";
  return d;
}

function StarburstImage({
  cx,
  cy,
  outerR,
  innerR,
  points,
  imageUri,
  clipId,
}: {
  cx: number;
  cy: number;
  outerR: number;
  innerR: number;
  points: number;
  imageUri: string;
  clipId: string;
}) {
  const d = starburstPath(cx, cy, outerR, innerR, points);
  return (
    <>
      <Defs>
        <ClipPath id={clipId}>
          <Path d={d} />
        </ClipPath>
      </Defs>
      <SvgImage
        x={cx - outerR}
        y={cy - outerR}
        width={outerR * 2}
        height={outerR * 2}
        href={{ uri: imageUri }}
        clipPath={`url(#${clipId})`}
        preserveAspectRatio="xMidYMid slice"
      />
      <Path d={d} fill="none" stroke="white" strokeWidth={3} />
    </>
  );
}

export function DualStarburstFrame({
  width = 300,
  height = 200,
  leftImageUri,
  rightImageUri,
}: {
  width?: number;
  height?: number;
  leftImageUri: string;
  rightImageUri: string;
}) {
  const outerR = height * 0.46;
  const innerR = outerR * 0.52;
  const numPoints = 8;

  const leftCx = width * 0.35;
  const rightCx = width * 0.65;
  const cy = height * 0.5;

  // ViewBox with padding so starbursts aren't clipped at edges
  const pad = outerR * 0.15;
  const vbX = leftCx - outerR - pad;
  const vbY = cy - outerR - pad;
  const vbW = rightCx + outerR + pad - vbX;
  const vbH = outerR * 2 + pad * 2;

  return (
    <View style={{ width, height }}>
      <Svg
        width={width}
        height={height}
        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
      >
        <StarburstImage
          cx={rightCx}
          cy={cy}
          outerR={outerR}
          innerR={innerR}
          points={numPoints}
          imageUri={rightImageUri}
          clipId="clip-right"
        />
        <StarburstImage
          cx={leftCx}
          cy={cy}
          outerR={outerR}
          innerR={innerR}
          points={numPoints}
          imageUri={leftImageUri}
          clipId="clip-left"
        />
      </Svg>
    </View>
  );
}

export function SingleStarburstFrame({
  size = 200,
  imageUri,
}: {
  size?: number;
  imageUri: string;
}) {
  const outerR = size * 0.46;
  const innerR = outerR * 0.52;
  const numPoints = 8;
  const cx = size / 2;
  const cy = size / 2;

  return (
    <View style={{ width: size, height: size }}>
      <Svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
        <StarburstImage
          cx={cx}
          cy={cy}
          outerR={outerR}
          innerR={innerR}
          points={numPoints}
          imageUri={imageUri}
          clipId="clip-single"
        />
      </Svg>
    </View>
  );
}

/**
 * Curvy starburst: smooth rounded petals using quadratic bezier curves
 * from valley to valley with control point at each petal tip.
 */
function curvyStarburstPath(
  cx: number,
  cy: number,
  outerR: number,
  innerR: number,
  numPetals: number
) {
  const step = (2 * Math.PI) / numPetals;
  let d = "";

  for (let i = 0; i < numPetals; i++) {
    const valleyAngle = step * i - Math.PI / 2;
    const petalAngle = valleyAngle + step / 2;

    const vx = cx + innerR * Math.cos(valleyAngle);
    const vy = cy + innerR * Math.sin(valleyAngle);

    const px = cx + outerR * Math.cos(petalAngle);
    const py = cy + outerR * Math.sin(petalAngle);

    if (i === 0) d += `M ${vx} ${vy} `;

    const nextValleyAngle = step * (i + 1) - Math.PI / 2;
    const nvx = cx + innerR * Math.cos(nextValleyAngle);
    const nvy = cy + innerR * Math.sin(nextValleyAngle);

    d += `Q ${px} ${py} ${nvx} ${nvy} `;
  }
  d += "Z";
  return d;
}

export function CurvyStarburstFrame({
  size = 180,
  imageUri,
}: {
  size?: number;
  imageUri: string;
}) {
  const outerR = size * 0.48;
  const innerR = outerR * 0.72;
  const numPetals = 10;
  const cx = size / 2;
  const cy = size / 2;
  const d = curvyStarburstPath(cx, cy, outerR, innerR, numPetals);

  return (
    <View style={{ width: size, height: size }}>
      <Svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
        <Defs>
          <ClipPath id="curvy-clip">
            <Path d={d} />
          </ClipPath>
        </Defs>
        <SvgImage
          x={cx - outerR}
          y={cy - outerR}
          width={outerR * 2}
          height={outerR * 2}
          href={{ uri: imageUri }}
          clipPath="url(#curvy-clip)"
          preserveAspectRatio="xMidYMid slice"
        />
        <Path d={d} fill="none" stroke="white" strokeWidth={3} />
      </Svg>
    </View>
  );
}

